# Validate a SAML assertion from Entra ID using python3-saml
from onelogin.saml2.auth import OneLogin_Saml2_Auth
from flask import request, session

SAML_SETTINGS = {
    'strict': True,
    'debug': False,
    'sp': {
        'entityId': 'https://app.example.com/saml/metadata',
        'assertionConsumerService': {
            'url': 'https://app.example.com/saml/acs',
            'binding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST',
        },
        'singleLogoutService': {
            'url': 'https://app.example.com/saml/slo',
            'binding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect',
        },
        'NameIDFormat': 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress',
        'x509cert': '',  # SP cert for encryption (optional)
        'privateKey': '', # SP private key (optional)
    },
    'idp': {
        'entityId': 'https://sts.windows.net/<tenant-id>/',
        'singleSignOnService': {
            'url': 'https://login.microsoftonline.com/<tenant-id>/saml2',
            'binding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect',
        },
        'singleLogoutService': {
            'url': 'https://login.microsoftonline.com/<tenant-id>/saml2',
            'binding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect',
        },
        # Download from Entra portal > Enterprise App > SAML > Certificate (Base64)
        'x509cert': '<base64-encoded-entra-signing-certificate>',
    },
}

@flask_app.route('/saml/acs', methods=['POST'])
def saml_acs():
    auth = OneLogin_Saml2_Auth(prepare_flask_request(request), SAML_SETTINGS)
    auth.process_response()
    errors = auth.get_errors()
    if errors:
        return f'SAML error: {errors}', 400
    if not auth.is_authenticated():
        return 'Not authenticated', 401
    # Extract user attributes from assertion
    attrs = auth.get_attributes()
    session['user'] = {
        'name_id':   auth.get_nameid(),
        'upn':       attrs.get('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/upn', [''])[0],
        'email':     attrs.get('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress', [''])[0],
        'groups':    attrs.get('http://schemas.microsoft.com/ws/2008/06/identity/claims/groups', []),
    }
    relay_state = request.form.get('RelayState', '/')
    return redirect(relay_state)

# Configure sign-in frequency and persistent session via Conditional Access
Connect-MgGraph -Scopes 'Policy.ReadWrite.ConditionalAccess'

# Policy 1: Require re-authentication every 8 hours for finance apps
$frequencyPolicy = @{
    displayName = 'Finance Apps - 8h Session Limit'
    state       = 'enabled'
    conditions  = @{
        users        = @{ includeGroups = @('<finance-group-id>') }
        applications = @{ includeApplications = @('<finance-app-client-id>') }
    }
    sessionControls = @{
        signInFrequency = @{
            isEnabled         = $true
            type              = 'hours'
            value             = 8
            authenticationType = 'primaryAndSecondaryAuthentication'
            frequencyInterval  = 'timeBased'
        }
        persistentBrowser = @{
            isEnabled = $true
            mode      = 'never'  # never show 'Stay signed in?'
        }
    }
}
New-MgIdentityConditionalAccessPolicy -BodyParameter $frequencyPolicy

# Policy 2: Every-time sign-in for privileged roles
$everyTimePolicy = @{
    displayName = 'Privileged Roles - Every Sign-In MFA'
    state       = 'enabled'
    conditions  = @{
        users        = @{ includeRoles = @('<global-admin-role-id>', '<privileged-role-admin-id>') }
        applications = @{ includeApplications = @('All') }
    }
    sessionControls = @{
        signInFrequency = @{
            isEnabled         = $true
            frequencyInterval  = 'everyTime'  # re-auth on every new session
            authenticationType = 'primaryAndSecondaryAuthentication'
        }
    }
}
New-MgIdentityConditionalAccessPolicy -BodyParameter $everyTimePolicy
